  const wd = (WEEKDAY_FAV[category] || WEEKDAY_FAV.general)[info.dow] ?? 0;
  s += wd;
  if (wd > 0) f.push({ t: WN_SHORT[info.dow], g: true }); else if (wd < 0) f.push({ t: WN_SHORT[info.dow] + " (weak)", g: false });
