  const aru = ev.rise - 96 * 60000;
  const viddha = tIdx(aru) === 9 || tIdx(aru) === 24;                 // Dashami touches Arunodaya
  const twoRise = tIdx(evN.rise) === 10 || tIdx(evN.rise) === 25;      // Ekadashi at both sunrises
